return [
  { payload: Number(msg.payload.EMG_raw) },
  { payload: msg.payload.EMG_state },
  { payload: Number(msg.payload.Flex_value) },
  { payload: msg.payload.Flex_state },
  { payload: Number(msg.payload.Heart_rate) },
  { payload: msg.payload.HR_state },
  { payload: Number(msg.payload.Temp_C) },
  { payload: msg.payload.Temp_state }
];

let patient = msg.req.query.patient;

if (!patient || !/^P00[1-3]$/.test(patient)) {
    msg.statusCode = 400;
    msg.payload = "❌ Patient ID no válido.";
    return msg;
}

let data = flow.get(patient);
if (!data || data.length === 0) {
    msg.statusCode = 404;
    msg.payload = `📭 No hay datos guardados para ${patient}`;
    return msg;
}

// Cabecera CSV con punto y coma
let csv = "Timestamp;Patient_ID;EMG_raw;EMG_state;Flex_value;Flex_state;Heart_rate;HR_state;Temp_C;Temp_state\n";

// Añadir filas con timestamp en hora local (España)
data.forEach(d => {
    let localDate = new Date(d.timestamp);
    let timestamp = localDate.toLocaleString("es-ES", {
        timeZone: "Europe/Madrid"
    });

    csv += `${timestamp};${d.Patient_ID};${d.EMG_raw};${d.EMG_state};${d.Flex_value};${d.Flex_state};${d.Heart_rate};${d.HR_state};${d.Temp_C};${d.Temp_state}\n`;
});

msg.payload = csv;
msg.headers = {
    "Content-Disposition": `attachment; filename=biomedical_data_${patient}.csv`,
    "Content-Type": "text/csv"
};
return msg;

let current = msg.payload;
let previous = flow.get("previous_patient") || "";

if (current !== previous && current !== "Select patient") {
    flow.set("previous_patient", current);
    return msg;  // solo deja pasar si ha cambiado de paciente
}

return null; // no hacer nada si se repite o es 'Select patient'

let hr = Number(msg.payload);

if (hr > 100) {
    msg.class = "hr-alert-red";
    msg.text = "⚠️ HR too high!";
} else if (hr < 50) {
    msg.class = "hr-alert-yellow";
    msg.text = "⚠️ HR too low!";
} else {
    msg.class = "hr-normal";
    msg.text = "✔️ Normal HR";
}
return msg;

let emg = Number(msg.payload);

if (emg > 100) {
    msg.class = "alert-red";
    msg.text = "⚠️ very high EMG";
} else if (emg < 50) {
    msg.class = "alert-yellow";
    msg.text = "⚠️ very low EMG";
} else {
    msg.class = "normal";
    msg.text = "✔️ Normal EMG";
}
return msg;

let temp = Number(msg.payload);

if (temp > 28) {
    msg.class = "alert-red";
    msg.text = "⚠️ High temperature";
} else if (temp < 20) {
    msg.class = "alert-yellow";
    msg.text = "⚠️ Low temperature";
} else {
    msg.class = "normal";
    msg.text = "✔️ Normal temperature";
}
return msg;

let flex = Number(msg.payload);

if (flex > 910) {
    msg.class = "alert-yellow";
    msg.text = "⚠️ Very little flexion";
} else if (flex > 870) {
    msg.class = "alert-yellow";
    msg.text = "✔️ Good flexion";
} else {
    msg.class = "normal";
    msg.text = "✔️ Very good flexion";
}
return msg;

let payload = msg.payload;

// Si es un string (probablemente JSON), lo convertimos a objeto
if (typeof payload === "string") {
    try {
        payload = JSON.parse(payload);
    } catch (err) {
        node.warn("❌ JSON inválido en payload");
        return null;
    }
}

// Validar que todos los campos críticos están presentes
if (
    !payload.Patient_ID ||
    payload.EMG_raw === undefined ||
    payload.Flex_value === undefined ||
    payload.Heart_rate === undefined ||
    payload.Temp_C === undefined
) {
    node.warn("❌ Campos incompletos. Registro ignorado.");
    return null;
}

// Crear el registro con timestamp y todos los campos
let registro = {
    timestamp: new Date().toISOString(),
    Patient_ID: payload.Patient_ID,
    EMG_raw: payload.EMG_raw,
    EMG_state: payload.EMG_state,
    Flex_value: payload.Flex_value,
    Flex_state: payload.Flex_state,
    Heart_rate: payload.Heart_rate,
    HR_state: payload.HR_state,
    Temp_C: payload.Temp_C,
    Temp_state: payload.Temp_state
};

// Acumular el registro en la memoria flow
let data = flow.get(payload.Patient_ID) || [];
data.push(registro);
flow.set(payload.Patient_ID, data);

// Reenviar el mensaje para su visualización
msg.payload = payload;
return msg;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "High EMG";
msg.value = val;
msg.patient_id = id;
msg.payload = `🚨 High EMG detected: ${val}`;
msg.isAlert = true;
return msg;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "Low EMG";
msg.value = val;
msg.patient_id = id;
msg.payload = `⚠️ Low EMG detected: ${val}`;
msg.isAlert = true;   
return msg;

let current = msg.payload;
let previous = flow.get("previous_patient") || "";
let ok = flow.get("admin_ok") || false;

// Solo procesar selecciones si el admin está autenticado
if (!ok) {
    return null;
}

if (current !== previous) {
    flow.set("previous_patient", current);
    // Dejar pasar incluso si es 'Select patient' para poder borrar info anterior
    return msg;
}

return null;

const id = msg.payload || "";
const ok = flow.get("admin_ok") || false;

let patients = {
    "P001": {
        firstName: "Ana",
        lastName: "García Pérez",
        age: 29,
        diagnosis: "Humeral fracture",
        status: "In rehabilitation",
        admissionDate: "2025-03-02",
        doctor: "Dr. López",
        treatment: "Physiotherapy + daily monitoring",
        notes: "Good progress"
    },
    "P002": {
        firstName: "Carlos",
        lastName: "Martínez Ruiz",
        age: 41,
        diagnosis: "Rotator cuff injury",
        status: "Stable",
        admissionDate: "2025-04-15",
        doctor: "Dr. Pérez",
        treatment: "Controlled passive exercises",
        notes: "Mild residual pain"
    },
    "P003": {
        firstName: "Lucía",
        lastName: "Fernández Gómez",
        age: 35,
        diagnosis: "Brachial plexus palsy",
        status: "Chronic",
        admissionDate: "2025-01-10",
        doctor: "Dr. Rivera",
        treatment: "EMG stimulation and functional therapy",
        notes: "No recent changes"
    }
};

// Solo mostrar datos si el admin está autenticado y se ha seleccionado un paciente válido
msg.payload = (ok && id in patients) ? patients[id] : null;
msg.admin_ok = ok;
return msg;

// Forward only if admin is authenticated
const ok = flow.get("admin_ok") || false;

if (ok) {
    // Usar el paciente actualmente seleccionado
    const currentPatient = flow.get("previous_patient") || "";
    msg.payload = currentPatient;
    return msg;
}

return null;

const ok = flow.get("admin_ok") || false;

// Si el admin acaba de iniciar sesión
if (ok) {
    // Reseteamos la selección de paciente para comenzar limpio
    flow.set("previous_patient", "");
    msg.payload = "Select patient";
    return msg;
}

return null;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "High Heart Rate";
msg.value = val;
msg.patient_id = id;
msg.payload = `🚨 High heart rate detected: ${val} bpm`;
msg.isAlert = true;
return msg;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "Low Heart Rate";
msg.value = val;
msg.patient_id = id;
msg.payload = `⚠️ Low heart rate detected: ${val} bpm`;
msg.isAlert = true;
return msg;

// Solo procesar el mensaje si es una alerta
if (msg.isAlert) {
    let alerts = flow.get("alert_log") || [];

    // Obtener el paciente actual desde flow
    let id = flow.get("patient_id") || "Unknown";

    // Crear alerta con ID del paciente seleccionado
    let new_alert = {
        timestamp: new Date().toLocaleString(),
        patient: id,  // 👈 aquí garantizamos que es el mismo que está seleccionado
        type: msg.alertType || "Alert",
        value: msg.value || "N/A",
        message: msg.payload
    };

    alerts.push(new_alert);
    flow.set("alert_log", alerts);

    // Mostrar solo las alertas del paciente seleccionado actualmente
    msg.payload = alerts.filter(a => a.patient === id);
    return msg;
}

return null;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "High Temp";
msg.value = val;
msg.patient_id = id;
msg.payload = `🚨 High Temperature detected: ${val}`;
msg.isAlert = true;
return msg;

let id = flow.get("patient_id") || "Unknown";
let val = Number(msg.payload);

msg.alertType = "Low Temp";
msg.value = val;
msg.patient_id = id;
msg.payload = `⚠️ Low temperature detected: ${val}`;
msg.isAlert = true;
return msg;
